class UserLocation{static get(t){navigator.geolocation?navigator.geolocation.getCurrentPosition((a=>{t({lat:a.coords.latitude,lng:a.coords.longitude})})):alert("Necesitas activar la ubicación")}}function calcularDistancia(t,a,n,o){const e=(n-t)*Math.PI/180,i=(o-a)*Math.PI/180,c=Math.sin(e/2)*Math.sin(e/2)+Math.cos(t*Math.PI/180)*Math.cos(n*Math.PI/180)*Math.sin(i/2)*Math.sin(i/2);return 6371*(2*Math.atan2(Math.sqrt(c),Math.sqrt(1-c)))}document.addEventListener("DOMContentLoaded",(function(){const t=-34.940517536528084,a=-58.03743728108097,n=L.map("map").setView([t,a],15);L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{attribution:"&copy; OpenStreetMap contributors"}).addTo(n),L.marker([t,a]).addTo(n).bindPopup("Alana Indumentaria").openPopup(),UserLocation.get((n=>{const o=calcularDistancia(n.lat,n.lng,t,a);document.querySelector("#message").i,console.log("Distancia en línea recta:",o.toFixed(2),"km")}))}));